  "title": "फ़्यू‑शॉट उदाहरण",
  "group": "प्रॉम्प्ट संरचना",
  "options": [
    {
      "text": "अधिक उदाहरण हमेशा बेहतर परिणाम देते हैं"
    },
    {
      "text": "प्रॉम्प्ट में 3–5 उच्च‑गुणवत्ता, विविध उदाहरण"
    },
    {
      "text": "फ़्यू‑शॉट उदाहरण केवल वर्गीकरण कार्यों में मदद करते हैं"
    },
    {
      "text": "उदाहरण उपयोगकर्ता क्वेरी के बाद होने चाहिए, पहले नहीं"
    }
  ],
  "questionProse": [
    "अधिकांश उत्पादन उपयोग मामलों के लिए, इष्टतम फ़्यू‑शॉट उदाहरण रणनीति है:"
  ],
  "explanationProse": [
    "फ़्यू‑शॉट उदाहरण आउटपुट की स्थिरता और फ़ॉर्मेट पालन को नाटकीय रूप से सुधारते हैं। अधिकांश कार्यों के लिए सही संतुलन **3–5 उच्च‑गुणवत्ता, विविध उदाहरण** है।\n\n    और क्यों नहीं? प्रत्येक उदाहरण टोकन खर्च करता है। 5–10 उदाहरणों से आगे, सीमांत लाभ घटता है जबकि टोकन लागत बढ़ती रहती है। अधिक उदाहरण मॉडल के उदाहरणों पर अधिक फ़िट होने की संभावना बढ़ाते हैं, न कि मूल पैटर्न को समझने की।\n\n    विविधता क्यों महत्वपूर्ण है: यदि सभी उदाहरण एक ही प्रकार के इनपुट हैं, तो मॉडल किनारी मामलों में अच्छी तरह सामान्यीकरण नहीं करेगा। अपने सबसे महत्वपूर्ण विविधताओं को कवर करने वाले उदाहरण शामिल करें।\n\n    स्थान: उदाहरण *उपयोगकर्ता क्वेरी से पहले* होने चाहिए, सिस्टम प्रॉम्प्ट का हिस्सा या पूर्व‑भरे संवाद टर्न के रूप में — बाद में नहीं।"
  ],
